  # Group triples by their subject to build concise clauses.
      from collections import defaultdict

      subject_to_phrases = defaultdict(list)
      for triple in triples:
          template = phrasing.get(triple.predicate)
          if template:
              phrase = template.format(triple.object)
          else:
              phrase = f"{triple.predicate} {triple.object}"
          subject_to_phrases[triple.subject].append(phrase)

      # Build a clause for each subject.
      subject_clauses = []
      for subject, phrases in subject_to_phrases.items():
          if len(phrases) == 1:
              clause_body = phrases[0]
          else:
              clause_body = ", ".join(phrases[:-1]) + " and " + phrases[-1]
          subject_clauses.append(f"{subject} {clause_body}")

      # Combine subject clauses into a single sentence.
      if len(subject_clauses) == 1:
          sentence = subject_clauses[0] + "."
      else:
          sentence = ", ".join(subject_clauses[:-1]) + " and " + subject_clauses[-1] + "."
